  /// download events.
  public var modelID: String = String()

  /// For COMPONENT_DOWNLOAD_REQUIRED — RN events.ts:285.
  public var sizeBytes: Int64 = 0

  /// For COMPONENT_DOWNLOAD_PROGRESS — 0.0..1.0.
  public var progress: Float = 0

  /// For COMPONENT_FAILED / *_FAILED.
  public var error: String = String()

  /// For COMPONENT_STATE_CHANGED — RN events.ts:274-278.
  public var oldState: String = String()

  public var newState: String = String()

  /// For multi-component events (initializationStarted / parallel/sequential /
  /// someComponentsReady).
  public var components: [RASDKComponent] = []

  public var readyComponents: [RASDKComponent] = []

  public var pendingComponents: [RASDKComponent] = []

  /// For INITIALIZATION_COMPLETED — InitializationResult summary
  /// (success bool + count). Full result travels via dedicated RPC.
  public var initSuccess: Bool = false

  public var readyCount: Int32 = 0

  public var failedCount: Int32 = 0

  public var unknownFields = SwiftProtobuf.UnknownStorage()

  public init() {}
}

/// ---------------------------------------------------------------------------
/// Top-level event envelope. Every event published by every SDK is wrapped in
/// exactly one `SDKEvent` — analytics consumers, app developers, and
/// pipelines all decode the same bytes.
///
/// `voice_pipeline` carries the streaming voice pipeline events from
/// `voice_events.proto` (UserSaid / AssistantToken / AudioFrame / VAD /
/// Interrupted / StateChange / Error / Metrics). Higher-level voice
/// lifecycle events live in this file's `voice` field.
/// ---------------------------------------------------------------------------
public struct RASDKEvent: @unchecked Sendable {
  // SwiftProtobuf.Message conformance is added in an extension below. See the
  // `Message` and `Message+*Additions` files in the SwiftProtobuf library for
  // methods supported on all messages.

  /// Wall-clock time of event creation, milliseconds since Unix epoch.
  public var timestampMs: Int64 {
    get {_storage._timestampMs}
    set {_uniqueStorage()._timestampMs = newValue}
  }

  public var severity: RAEventSeverity {
    get {_storage._severity}
    set {_uniqueStorage()._severity = newValue}
  }

  /// Event identifier (UUID). Required by Swift SDKEvent.id /
  /// Kotlin SDKEvent.id / Dart SDKEvent.id for de-duplication.
  public var id: String {
    get {_storage._id}
    set {_uniqueStorage()._id = newValue}
  }

  /// Optional session id for grouping related events
  /// (Swift sessionId / Kotlin sessionId / Dart sessionId).
  public var sessionID: String {
    get {_storage._sessionID}
    set {_uniqueStorage()._sessionID = newValue}
  }

  /// Event routing destination (Swift EventDestination, Kotlin
  /// EventDestination, Dart EventDestination).
  public var destination: RAEventDestination {
    get {_storage._destination}
    set {_uniqueStorage()._destination = newValue}
  }

  /// Free-form metadata for properties not modeled above
  /// (mirrors `properties: Map<String, String>` from each SDK).
  public var properties: Dictionary<String,String> {
    get {_storage._properties}
    set {_uniqueStorage()._properties = newValue}
  }

  public var event: OneOf_Event? {
    get {return _storage._event}
    set {_uniqueStorage()._event = newValue}
  }

  public var initialization: RAInitializationEvent {
    get {
      if case .initialization(let v)? = _storage._event {return v}
      return RAInitializationEvent()
    }
    set {_uniqueStorage()._event = .initialization(newValue)}
  }

  public var configuration: RAConfigurationEvent {
    get {
      if case .configuration(let v)? = _storage._event {return v}
      return RAConfigurationEvent()
    }
    set {_uniqueStorage()._event = .configuration(newValue)}
  }

  public var generation: RAGenerationEvent {
    get {
      if case .generation(let v)? = _storage._event {return v}
      return RAGenerationEvent()
    }
    set {_uniqueStorage()._event = .generation(newValue)}
  }

  public var model: RAModelEvent {
    get {
      if case .model(let v)? = _storage._event {return v}
      return RAModelEvent()
    }
    set {_uniqueStorage()._event = .model(newValue)}
  }

  public var performance: RAPerformanceEvent {
    get {
      if case .performance(let v)? = _storage._event {return v}
      return RAPerformanceEvent()
    }
    set {_uniqueStorage()._event = .performance(newValue)}
  }

  public var network: RANetworkEvent {
    get {
      if case .network(let v)? = _storage._event {return v}
      return RANetworkEvent()
    }
    set {_uniqueStorage()._event = .network(newValue)}
  }

  public var storage: RAStorageEvent {
    get {
      if case .storage(let v)? = _storage._event {return v}
      return RAStorageEvent()
    }
    set {_uniqueStorage()._event = .storage(newValue)}
  }

  public var framework: RAFrameworkEvent {
    get {
      if case .framework(let v)? = _storage._event {return v}
      return RAFrameworkEvent()
    }
    set {_uniqueStorage()._event = .framework(newValue)}
  }

  public var device: RADeviceEvent {
    get {
      if case .device(let v)? = _storage._event {return v}
      return RADeviceEvent()
    }
    set {_uniqueStorage()._event = .device(newValue)}
  }

  public var componentInit: RAComponentInitializationEvent {
    get {
      if case .componentInit(let v)? = _storage._event {return v}
      return RAComponentInitializationEvent()
    }
    set {_uniqueStorage()._event = .componentInit(newValue)}
  }

  public var voice: RAVoiceLifecycleEvent {
    get {
      if case .voice(let v)? = _storage._event {return v}
      return RAVoiceLifecycleEvent()
    }
    set {_uniqueStorage()._event = .voice(newValue)}
  }

  /// from voice_events.proto
  public var voicePipeline: RAVoiceEvent {
    get {
      if case .voicePipeline(let v)? = _storage._event {return v}
      return RAVoiceEvent()
    }
    set {_uniqueStorage()._event = .voicePipeline(newValue)}
  }

  public var unknownFields = SwiftProtobuf.UnknownStorage()

  public enum OneOf_Event: Equatable, Sendable {
    case initialization(RAInitializationEvent)
    case configuration(RAConfigurationEvent)
    case generation(RAGenerationEvent)
    case model(RAModelEvent)
    case performance(RAPerformanceEvent)
    case network(RANetworkEvent)
    case storage(RAStorageEvent)
    case framework(RAFrameworkEvent)
    case device(RADeviceEvent)
    case componentInit(RAComponentInitializationEvent)
    case voice(RAVoiceLifecycleEvent)
    /// from voice_events.proto
    case voicePipeline(RAVoiceEvent)

  }

  public init() {}

  fileprivate var _storage = _StorageClass.defaultInstance
}

